+	return DefaultBaseURL + "/" + url.PathEscape(c.Org) + "/" + url.PathEscape(c.Project) + "/_apis"
+}
+
+// orgBase returns the org-level _apis URL prefix (not project-scoped).
+func (c *Client) orgBase() string {
