+			w.WriteHeader(http.StatusOK)
+			_, _ = w.Write([]byte(resp))
+			step++
+
+		case strings.Contains(r.URL.Path, "/wit/workitems"):
+			// Batch GET step.
+			if step == 0 {
+				t.Error("batch GET called before WIQL")
+			}
